<?php
namespace App\Console\Commands; use App\Models\User; use Illuminate\Console\Command; use Illuminate\Support\Facades\Hash;
class CreateAdmin extends Command {protected $signature='admin:create';protected $description='Create an administrator account interactively.';public function handle():int{$name=$this->ask('ชื่อผู้ดูแล');$email=$this->ask('อีเมล');if(User::where('email',$email)->exists()){ $this->error('อีเมลนี้ถูกใช้งานแล้ว');return self::FAILURE;}$password=$this->secret('รหัสผ่าน (อย่างน้อย 8 ตัวอักษร)');if($password!==$this->secret('ยืนยันรหัสผ่าน')){$this->error('รหัสผ่านไม่ตรงกัน');return self::FAILURE;}User::create(['name'=>$name,'email'=>$email,'password'=>Hash::make($password),'role'=>'admin']);$this->info('สร้างบัญชีผู้ดูแลแล้ว');return self::SUCCESS;}}
